sql:
SELECT test_id
FROM benchmark_tests
ORDER BY test_id;

SELECT test_name, system_time
FROM benchmark_tests
ORDER BY system_time DESC;

SELECT test_type, AVG(system_time) AS avg_system_time
FROM benchmark_tests
GROUP BY test_type;

SELECT test_name
FROM benchmark_tests
WHERE system_time = (
    SELECT MAX(system_time)
    FROM benchmark_tests
);

SELECT test_id, test_name
FROM benchmark_tests
ORDER BY test_id;

